<?php require_once 'config.php'; require_auth(); $q=$_GET['q']??''; $st=db()->prepare('SELECT wo.*,c.name client_name,c.phone,v.brand,v.model,v.plate FROM work_orders wo JOIN clients c ON c.id=wo.client_id JOIN vehicles v ON v.id=wo.vehicle_id WHERE wo.code LIKE ? OR c.name LIKE ? OR v.plate LIKE ? ORDER BY wo.updated_at DESC'); $like="%$q%"; $st->execute([$like,$like,$like]); $rows=$st->fetchAll(); include 'partials/header.php'; ?>
<section class="card"><div class="actions"><h1 style="flex:1">Órdenes</h1><a class="btn primary" href="order_new.php">+ Nueva</a></div><form><input name="q" placeholder="Buscar por orden, cliente o patente" value="<?=h($q)?>"></form><table><tr><th>Orden</th><th>Cliente</th><th>Moto</th><th>Estado</th><th>Actualizada</th><th></th></tr><?php foreach($rows as $r):?><tr><td><?=h($r['code'])?></td><td><?=h($r['client_name'])?><br><small class="muted"><?=h($r['phone'])?></small></td><td><?=h($r['brand'].' '.$r['model'])?><br><small class="muted"><?=h($r['plate'])?></small></td><td><span class="status"><?=h($r['current_status'])?></span></td><td><?=h($r['updated_at'])?></td><td><a class="btn" href="order_view.php?id=<?=$r['id']?>">Abrir</a></td></tr><?php endforeach;?></table></section><?php include 'partials/footer.php'; ?>
